-- Tenancy: the BRAND_PREDICATE sentinel (below) is replaced with `brand_id = ?` by the serving seam.
CREATE OR REPLACE VIEW brain_serving.mv_metric_ad_spend_all AS
WITH base AS (
  SELECT
    brand_id,
    currency_code,
    platform,
    SUM(spend_minor) AS spend_minor
  FROM brain_serving.semantic_campaign
  WHERE ${BRAND_PREDICATE}
  GROUP BY 1, 2, 3
)
SELECT
  brand_id,
  currency_code,
  platform,
  spend_minor,
  (spend_minor) AS ad_spend
FROM base;
